{
  "validationGates": [
    {
      "name": "SyntaxCheck",
      "targets": ["js", "ts"],
      "action": "Run ESLint and Typescript compiler",
      "failurePolicy": "fail-fast",
      "excludeModelKeys": []
    },
    {
      "name": "SQLMigrationValidation",
      "targets": ["sql"],
      "action": "Run SQL linter and dry-run migration against test DB",
      "failurePolicy": "fail-fast",
      "excludeModelKeys": []
    },
    {
      "name": "CloudflareWorkerCheck",
      "targets": ["cloudflare-worker"],
      "action": "Bundle with Wrangler, run preview, matches route/pattern, check for cf-specific API usage",
      "failurePolicy": "fail",
      "excludeModelKeys": []
    },
    {
      "name": "DashboardBrowserCheck",
      "targets": ["dashboard", "browser"],
      "action": "Launch headless browser, run smoke and health checks on dashboard endpoints",
      "failurePolicy": "continue-on-failure",
      "excludeModelKeys": ["internalMetricModels", "test-only"]
    },
    {
      "name": "ExcludeModelKeysEnforcement",
      "targets": ["js", "ts", "sql", "dashboard", "cloudflare-worker"],
      "action": "Block patches affecting excluded model keys",
      "failurePolicy": "fail",
      "excludeModelKeys": ["deprecated", "sensitiveSecrets", "doNotPatch"]
    }
  ]
}
